import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.TWA1q3r6.js";const b=JSON.parse('{"title":"🚀 6-12M · 移动革命期","description":"","frontmatter":{"title":"🚀 6-12M · 移动革命期"},"headers":[],"relativePath":"stages/6-12m.md","filePath":"stages/6-12m.md"}'),o={name:"stages/6-12m.md"};function s(n,t,i,l,h,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="🚀-6-12m-·-移动革命期" tabindex="-1">🚀 6-12M · 移动革命期 <a class="header-anchor" href="#🚀-6-12m-·-移动革命期" aria-label="Permalink to &quot;🚀 6-12M · 移动革命期&quot;">​</a></h1><blockquote><p>客厅不再是客厅，它现在是探险基地、餐厅，偶尔还是战场。</p><p>从坐稳到爬行，从第一口米粉到自己抓着吃 —— 这是独立的起点。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>大运动</td><td><strong>自由爬行</strong>（非学步车）</td><td>交叉模式运动协调 + 深度知觉 + 前庭发育</td><td>提供安全爬行空间</td><td>AAP</td></tr><tr><td>认知</td><td><strong>躲猫猫 / 藏东西</strong></td><td>客体永恒性：东西藏起来 ≠ 消失 → 工作记忆原型</td><td>每天几次，每次1-3min</td><td>Piaget</td></tr><tr><td>语言</td><td><strong>指认命名</strong> Point &amp; Name</td><td>指着说&quot;这是苹果&quot; = 联合注意力，语言习得核心</td><td>融入吃饭/外出</td><td>Tomasello</td></tr><tr><td>饮食</td><td><strong>BLW自主进食</strong></td><td>手指食物促精细运动 + 咀嚼肌 + 进食兴趣</td><td>每餐提供手指食物</td><td>AAP</td></tr></tbody></table><hr><h2 id="🛡️-装备清单" tabindex="-1">🛡️ 装备清单 <a class="header-anchor" href="#🛡️-装备清单" aria-label="Permalink to &quot;🛡️ 装备清单&quot;">​</a></h2><h3 id="安全必备" tabindex="-1">安全必备 <a class="header-anchor" href="#安全必备" aria-label="Permalink to &quot;安全必备&quot;">​</a></h3><h4 id="🥣-铁强化米粉-essential" tabindex="-1">🥣 铁强化米粉 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🥣-铁强化米粉-essential" aria-label="Permalink to &quot;🥣 铁强化米粉 Essential&quot;">​</a></h4><p>6个月后母乳铁储备耗尽，缺铁影响神经发育。辅食的第一口，也是最重要的一口。（AAP/WHO）</p><p><strong>选购</strong> 嘉宝(Gerber) / Earth&#39;s Best / 小皮(Little Freddie)，¥30-60/盒</p><h4 id="🚧-安全门-防护栏-essential" tabindex="-1">🚧 安全门 / 防护栏 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🚧-安全门-防护栏-essential" aria-label="Permalink to &quot;🚧 安全门 / 防护栏 Essential&quot;">​</a></h4><p>爬行期跌落是首位意外伤害原因。楼梯口、厨房、阳台 —— 所有高危区域都要装上。（CDC/CPSC）</p><p><strong>选购</strong> BabyDan / 攸曼诚品 / Regalo，¥100-300/个</p><h4 id="🔌-插座保护盖-essential" tabindex="-1">🔌 插座保护盖 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🔌-插座保护盖-essential" aria-label="Permalink to &quot;🔌 插座保护盖 Essential&quot;">​</a></h4><p>会爬的宝宝对插座有迷之执念。几块钱的保护盖，预防触电。（CPSC）</p><p><strong>选购</strong> 确保3C认证即可，品牌不重要，¥10-30/套</p><h3 id="吃饭装备" tabindex="-1">吃饭装备 <a class="header-anchor" href="#吃饭装备" aria-label="Permalink to &quot;吃饭装备&quot;">​</a></h3><h4 id="🪑-餐椅-带安全带-essential" tabindex="-1">🪑 餐椅（带安全带） <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🪑-餐椅-带安全带-essential" aria-label="Permalink to &quot;🪑 餐椅（带安全带） Essential&quot;">​</a></h4><p>固定体位降低呛噎和跌落风险，建立规律进食习惯。从第一口辅食就需要。</p><p><strong>选购</strong></p><table tabindex="0"><thead><tr><th>推荐</th><th>品牌</th><th>亮点</th><th>入手价</th></tr></thead><tbody><tr><td>终身之选</td><td>Stokke Tripp Trapp</td><td>1972年经典 + 终身使用 + 承重136kg + 残值50-60%</td><td>≤¥1,800（618/双11）</td></tr><tr><td>设计师同源</td><td>Nomi by Evomove</td><td>Peter Opsvik晚年作品，更轻，单手可调</td><td>—</td></tr><tr><td>ROI之王</td><td>IKEA ANTILOP</td><td>¥99 + 满足全部安全标准</td><td>¥99</td></tr><tr><td>国产优选</td><td>可优比(KUB)实木</td><td>对标TT结构 + 榉木 + TT 25%价格</td><td>—</td></tr></tbody></table><h4 id="🥤-学饮杯-conditional" tabindex="-1">🥤 学饮杯 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🥤-学饮杯-conditional" aria-label="Permalink to &quot;🥤 学饮杯 Conditional&quot;">​</a></h4><p>AAP建议6-12M开始练习开口杯，促进口腔肌肉发育。</p><p><strong>选购</strong> b.box / Munchkin 360 / NUK，¥50-150</p><h3 id="情感安抚" tabindex="-1">情感安抚 <a class="header-anchor" href="#情感安抚" aria-label="Permalink to &quot;情感安抚&quot;">​</a></h3><h4 id="🧸-安抚物-lovey-conditional" tabindex="-1">🧸 安抚物 Lovey <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🧸-安抚物-lovey-conditional" aria-label="Permalink to &quot;🧸 安抚物 Lovey Conditional&quot;">​</a></h4><p>12月龄后可以引入，有自我安慰功能。<strong>1岁前勿放床内</strong>（SIDS风险）。</p><p><strong>选购</strong> Jellycat / aden+anais 安抚巾，¥50-300</p><div class="danger custom-block"><p class="custom-block-title">❌ 避坑清单</p><ul><li><strong>学步车 Baby Walker</strong> — AAP明确反对，每年数千例急诊。替代：学步推车或自由扶站，让宝宝按自己的节奏来</li></ul></div><hr><h2 id="🌟-6m-家庭多巴胺准备金" tabindex="-1">🌟 6M+ 家庭多巴胺准备金 <a class="header-anchor" href="#🌟-6m-家庭多巴胺准备金" aria-label="Permalink to &quot;🌟 6M+ 家庭多巴胺准备金&quot;">​</a></h2><blockquote><p>户外时间变成发育刚需，这些小物件让出门从&quot;任务&quot;变&quot;享受&quot;。</p></blockquote><table tabindex="0"><thead><tr><th>物品</th><th>为什么值得</th><th>参考方向</th><th>预算</th></tr></thead><tbody><tr><td>🧺 亲子野餐垫</td><td>户外≥1h/天是发育刚需，好垫子改变出门心情</td><td>Snow Peak / 牧高笛</td><td>¥100-400</td></tr><tr><td>🍽️ 分餐盘（侘寂美学）</td><td>辅食每天3次上桌，餐具颜值影响喂养心情</td><td>Mushie / EZPZ</td><td>¥80-200</td></tr><tr><td>🎒 一个好用的妈咪包</td><td>出门频率骤增，&quot;好看到不像妈咪包&quot;是核心需求</td><td>Dagne Dover / 无印良品</td><td>¥200-1,000</td></tr><tr><td>📸 家庭相册（年度制）</td><td>每年精选36张做实体相册 &gt; 手机里10,000张</td><td>小米 / Artifact Uprising</td><td>¥50-300/年</td></tr></tbody></table>',34)])])}const u=a(o,[["render",s]]);export{b as __pageData,u as default};
